section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/freelancer-scope-change-script-library.json",
  "title": "Freelancer Scope-Change Script Library",
  "type": "object",
  "required": [
    "artefact_id",
    "situation_type",
    "empathy_line",
    "impact_line",
    "options",
    "next_step",
    "trigger_quote",
    "status",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "situation_type": {
      "type": "string",
      "description": "small-ask|big-ask|mission-creep|emergency",
      "minLength": 1
    },
    "empathy_line": {
      "type": "string",
      "description": "one-sentence acknowledgement of the client's pressure",
      "minLength": 1
    },
    "impact_line": {
      "type": "string",
      "description": "one-sentence statement of cost (time, money, sequence)",
      "minLength": 1
    },
    "options": {
      "type": "array",
      "description": "\u22652 named options each with price + timeline tradeoff",
      "minItems": 1
    },
    "next_step": {
      "type": "string",
      "description": "single concrete proposal (call slot, written agreement, escalation)",
      "minLength": 1
    },
    "trigger_quote": {
      "type": "string",
      "description": "verbatim 1-2 sentence quote of the client's ask",
      "minLength": 1
    }
  },
  "additionalProperties": false
}
